noncompliant:
struct myStruct {  // Noncompliant: should start with capital letter
  int one;
  int two;
};

struct my_struct {  // Noncompliant: underscore not allowed
  int value;
};

struct ALLCAPS {  // Noncompliant: all caps not recommended
  char data;
};

compliant:
struct MyStruct {  // Compliant: PascalCase
  int one;
  int two;
};

struct Person {  // Compliant
  char name[50];
  int age;
};

struct FileDescriptor {  // Compliant
  int fd;
  char *filename;
};
